    {
        var ex = Assert.ThrowsExactly<ArgumentException>(
            () => _formatter.FormatPhoneNumber(digits));

        Assert.AreEqual("digits", ex.ParamName);
    }

    // ── BuildGreeting ──────────────────────────────────────────────

    [TestMethod]
    public void BuildGreeting_NameOnly_UsesDefaultTitle()
    {
        var result = _formatter.BuildGreeting("Smith");

        Assert.AreEqual("Dear Mr. Smith,", result);
    }

    [TestMethod]
    public void BuildGreeting_WithTitle_StartsWithDear()
    {
        var result = _formatter.BuildGreeting("Jones", "Dr.");

        Assert.StartsWith("Dear", result);
    }

    [TestMethod]
    public void BuildGreeting_WithTitle_EndsWithComma()
    {
        var result = _formatter.BuildGreeting("Jones", "Dr.");

        Assert.EndsWith(",", result);
    }

    [TestMethod]
    public void BuildGreeting_WithTitle_ContainsName()
    {
        var result = _formatter.BuildGreeting("Jones", "Dr.");

        Assert.Contains("Jones", result);
    }

    [TestMethod]
    public void BuildGreeting_CustomTitle_IncludesTitle()
    {
        var result = _formatter.BuildGreeting("Doe", "Ms.");

        Assert.AreEqual("Dear Ms. Doe,", result);
    }

    [TestMethod]
    [DataRow(null, DisplayName = "Null name")]
    [DataRow("", DisplayName = "Empty name")]
    [DataRow("   ", DisplayName = "Whitespace name")]
    public void BuildGreeting_InvalidName_ThrowsArgumentException(string? name)
    {
        Assert.ThrowsExactly<ArgumentException>(
            () => _formatter.BuildGreeting(name!));
    }

    // ── GenerateSlug ───────────────────────────────────────────────

    [TestMethod]
    [DataRow("Hello World", "hello-world")]
    [DataRow("  My Blog Post  ", "my-blog-post")]
    [DataRow("C# is GREAT!", "c-is-great")]
    [DataRow("one---two", "one-two")]
    public void GenerateSlug_VariousInputs_ReturnsExpectedSlug(string title, string expected)
    {
        var result = _formatter.GenerateSlug(title);

        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    public void GenerateSlug_ValidTitle_MatchesSlugPattern()
    {
        var result = _formatter.GenerateSlug("Some Title Here!");

        Assert.MatchesRegex(@"^[a-z0-9]+(-[a-z0-9]+)*$", result);
    }

    [TestMethod]
    public void GenerateSlug_TitleWithSpecialChars_DoesNotStartWithHyphen()
    {
        var result = _formatter.GenerateSlug("!!!Hello");

        Assert.StartsWith("h", result);
    }

    [TestMethod]
    public void GenerateSlug_TitleWithTrailingSpecialChars_DoesNotEndWithHyphen()
    {
        var result = _formatter.GenerateSlug("Hello!!!");

        Assert.EndsWith("o", result);
    }

